    public boolean checkSubarraySum(int[] nums, int k) {
        int n = nums.length;
        int[] prefixSum = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = (prefixSum[i] + nums[i]) % k;
        }
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if ((prefixSum[j + 1] - prefixSum[i]) % k == 0) {
                    return true;
                }
            }
        }
        return false;
    }
}```
